func TestResolveEnabledTools(t *testing.T) {
	t.Run("nil config exposes all", func(t *testing.T) {
		enabled, err := resolveEnabledTools(nil)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if len(enabled) == 0 {
			t.Error("should expose all tools, got empty set")
		}
	})

	t.Run("nil expose exposes all", func(t *testing.T) {
		cfg := &mcputils.Config{}
		enabled, err := resolveEnabledTools(cfg)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if len(enabled) == 0 {
			t.Error("should expose all tools, got empty set")
		}
	})

	t.Run("register all by default with excludes", func(t *testing.T) {
		cfg := &mcputils.Config{
			Tools: mcputils.ToolsConfig{
				Expose: &mcputils.ToolsExposeConfig{
					RegisterAllToolsByDefault: true,
					Excludes:                  []string{"SomeTool"},
				},
			},
		}
		enabled, err := resolveEnabledTools(cfg)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if enabled["SomeTool"] {
			t.Error("SomeTool should be excluded")
		}
	})

	t.Run("whitelist only", func(t *testing.T) {
		cfg := &mcputils.Config{
			Tools: mcputils.ToolsConfig{
				Expose: &mcputils.ToolsExposeConfig{
					RegisterAllToolsByDefault: false,
					Includes:                  []string{"ToolA", "ToolB"},
				},
			},
		}
		enabled, err := resolveEnabledTools(cfg)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if !enabled["ToolA"] || !enabled["ToolB"] {
			t.Error("ToolA and ToolB should be enabled")
		}
		if len(enabled) != 2 {
			t.Errorf("expected only 2 tools, got %d", len(enabled))
		}
	})

	t.Run("conflict between includes and excludes", func(t *testing.T) {
		cfg := &mcputils.Config{
			Tools: mcputils.ToolsConfig{
				Expose: &mcputils.ToolsExposeConfig{
					Includes: []string{"ToolA"},
					Excludes: []string{"ToolA"},
				},
			},
		}
		_, err := resolveEnabledTools(cfg)
		if err == nil {
			t.Error("expected error for conflict")
		}
	})

	t.Run("empty includes and excludes", func(t *testing.T) {
		cfg := &mcputils.Config{
			Tools: mcputils.ToolsConfig{
				Expose: &mcputils.ToolsExposeConfig{
					RegisterAllToolsByDefault: false,
				},
			},
		}
		enabled, err := resolveEnabledTools(cfg)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if len(enabled) != 0 {
			t.Errorf("expected empty set, got %d tools", len(enabled))
		}
	})
}

func TestConvertResult(t *testing.T) {
	r := &mcp.CallToolResult{
		Content: []mcp.Content{
			mcp.TextContent{Type: "text", Text: "hello"},
			mcp.TextContent{Type: "text", Text: "world"},
		},
		IsError: true,
	}
	result := convertResult(r)
	if !result.IsError {
		t.Error("IsError should be true")
	}
	if len(result.Content) != 2 {
		t.Errorf("expected 2 content items, got %d", len(result.Content))
	}
	if result.Content[0].Text != "hello" {
		t.Errorf("got %q, want hello", result.Content[0].Text)
	}

	t.Run("empty result", func(t *testing.T) {
		r := &mcp.CallToolResult{}
		result := convertResult(r)
		if result.IsError {
			t.Error("IsError should be false")
		}
		if len(result.Content) != 0 {
			t.Errorf("expected 0 content items, got %d", len(result.Content))
		}
	})
}

func TestConvertAggResult(t *testing.T) {
	r := &pipeline.CallToolResult{
		Content: []pipeline.ContentItem{
			{Type: "text", Text: "result1"},
		},
		IsError: false,
	}
	result := convertAggResult(r)
	if result.IsError {
		t.Error("IsError should be false")
	}
	if len(result.Content) != 1 {
		t.Errorf("expected 1 content item, got %d", len(result.Content))
	}

	t.Run("error result", func(t *testing.T) {
		r := &pipeline.CallToolResult{
			Content: []pipeline.ContentItem{
				{Type: "text", Text: "error occurred"},
			},
			IsError: true,
		}
		result := convertAggResult(r)
		if !result.IsError {
			t.Error("IsError should be true")
		}
	})

	t.Run("multiple content items", func(t *testing.T) {
		r := &pipeline.CallToolResult{
			Content: []pipeline.ContentItem{
				{Type: "text", Text: "part1"},
				{Type: "text", Text: "part2"},
				{Type: "text", Text: "part3"},
			},
		}
		result := convertAggResult(r)
		if len(result.Content) != 3 {
			t.Errorf("expected 3 items, got %d", len(result.Content))
		}
	})
}

