	t.Run("empty description falls back to name", func(t *testing.T) {
		entry := pipeline.VirtualToolEntry{
			Name: "ToolNameAsDesc",
			InputSchema: map[string]interface{}{
				"type": "object",
			},
		}
		tool := buildVirtualMCPTool(entry)
		if tool.Description != "ToolNameAsDesc" {
			t.Errorf("description: got %q, want ToolNameAsDesc", tool.Description)
		}
	})

	t.Run("with annotations", func(t *testing.T) {
		entry := pipeline.VirtualToolEntry{
			Name:        "AnnotatedTool",
			Description: "Has annotations",
			InputSchema: map[string]interface{}{
				"type": "object",
			},
			Annotations: map[string]interface{}{
				"title":        "My Title",
				"readOnlyHint": true,
			},
		}
		tool := buildVirtualMCPTool(entry)
		if tool.Annotations.Title != "My Title" {
			t.Errorf("title: got %q", tool.Annotations.Title)
		}
		if tool.Annotations.ReadOnlyHint == nil || !*tool.Annotations.ReadOnlyHint {
			t.Error("readOnlyHint should be true")
		}
	})
