func TestRegistryAdapter_CallTool(t *testing.T) {
	adapter := &registryAdapter{}

	t.Run("non-existent tool", func(t *testing.T) {
		_, err := adapter.CallTool(context.Background(), "NonExistentTool", nil)
		if err == nil {
			t.Error("expected error for non-existent tool")
		}
	})

	t.Run("existing tool", func(t *testing.T) {
		for name := range mcptools.Registry {
			_, err := adapter.CallTool(context.Background(), name, map[string]interface{}{})
			if err != nil {
				t.Logf("tool %s call error (expected without upstream): %v", name, err)
			}
			break
		}
	})
}

func TestTruncate(t *testing.T) {
	t.Run("shorter than max", func(t *testing.T) {
		got := truncate("hello", 10)
		if got != "hello" {
			t.Errorf("got %q", got)
		}
	})
	t.Run("longer than max", func(t *testing.T) {
		got := truncate("hello world", 5)
		if got != "hello..." {
			t.Errorf("got %q", got)
		}
	})
	t.Run("exact length", func(t *testing.T) {
		got := truncate("hello", 5)
		if got != "hello" {
			t.Errorf("got %q", got)
		}
	})
	t.Run("empty", func(t *testing.T) {
		got := truncate("", 10)
		if got != "" {
			t.Errorf("got %q", got)
		}
	})
}

func TestBuildVirtualHandler(t *testing.T) {
	called := false
	entry := pipeline.VirtualToolEntry{
		Name: "TestHandler",
		Handler: func(ctx context.Context, args map[string]interface{}) (*pipeline.CallToolResult, error) {
			called = true
			return &pipeline.CallToolResult{
				Content: []pipeline.ContentItem{
					{Type: "text", Text: "result"},
				},
			}, nil
		},
	}

	handler := buildVirtualHandler(entry)
	req := mcp.CallToolRequest{
		Params: mcp.CallToolParams{
			Name:      "TestHandler",
			Arguments: map[string]interface{}{"key": "value"},
		},
	}
	result, err := handler(context.Background(), req)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if !called {
		t.Error("handler was not called")
	}
	if result == nil {
		t.Fatal("result is nil")
	}

	t.Run("nil args", func(t *testing.T) {
		called = false
		req := mcp.CallToolRequest{
			Params: mcp.CallToolParams{
				Name: "TestHandler",
			},
		}
		result, err := handler(context.Background(), req)
		if err != nil {
			t.Fatalf("unexpected error: %v", err)
		}
		if !called {
			t.Error("handler should be called even with nil args")
		}
		if result == nil {
			t.Fatal("result is nil")
		}
	})
}

